import { Component, OnInit } from '@angular/core';
import { CategoryService } from '../services/category.service';
import { Category } from '../models/category.model';
import { Observable } from 'rxjs';
import { Router } from '@angular/router';
import Swal from 'sweetalert2';


@Component({
  selector: 'app-categories-list',
  templateUrl: './categories-list.component.html',
  styleUrls: ['./categories-list.component.css']
})
export class CategoriesListComponent  implements OnInit {

  categories$?: Observable<Category[]>
  id:string | null = null

  constructor(private categoryService: CategoryService, private router: Router){

  }
  ngOnInit(): void {
    this.categories$ = this.categoryService.getAllCategories()

  }

  onDelete(id: string): void {
    Swal.fire({
      title: "Tem certeza?",
      text: "Essa ação não pode ser desfeita!",
      icon: "warning",
      showCancelButton: true,
      confirmButtonColor: "#d33",
      cancelButtonColor: "#3085d6",
      confirmButtonText: "Sim, excluir!",
      cancelButtonText: "Cancelar"
    }).then((result) => {
      if (result.isConfirmed) {
        this.categoryService.deleteCategory(id).subscribe({
          next: () => {
            Swal.fire("Deletado!", "A categoria foi removida com sucesso.", "success");
            this.categories$ = this.categoryService.getAllCategories();
          },
          error: (err) => {
            console.error("Erro ao excluir categoria:", err);
            Swal.fire("Erro!", "Ocorreu um problema ao excluir a categoria.", "error");
          }
        });
      }
    });
  }


}
<div class="container">
    <h1 class="mt-3">Category List</h1>
    <div class="d-flex justify-content-end mt-3">
        <a  class="btn btn-primary " [routerLink]="['/admin/categories/add']">add category</a>
    </div>
    <ng-container *ngIf="categories$ | async as categories">
        <table class="table table-bordered mt-3">
            <thead>
                <tr>
                    <th>id</th>
                    <th>name</th>
                    <th>url handle</th>
                    <th></th>


                </tr>
            </thead>
            <tbody>
                <tr *ngFor="let category of categories">
                    <td>{{category.id}}</td>
                    <td>{{category.name}}</td>
                    <td>{{category.urlHandle}}</td>
                    <td class="d-flex">
                        <a class="btn btn-light" [routerLink]="['/admin/categories', category.id]">Edit</a>
                        <button type="button" class="btn btn-danger ms-3" (click)="onDelete(category.id)" >delete</button>
                    </td>

                </tr>
            </tbody>

        </table>
    </ng-container>
</div>
